## Section1(not reported)
## Problem1(1.5.8.2)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PGchoicemacros.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "parserPopUp.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
do {
  ($x,$y) = (-8..8)[NchooseK(17,2)];
  @h = (-9..$x-1,$x+1..9)[NchooseK(18,2)];
  @k = (-9..$y-1,$y+1..9)[NchooseK(18,2)];
  Context("Fraction");
  Context()->noreduce('(-x)+y', '(-x)-y');
  @m = map{Fraction(($y - $k[$_])/($x - $h[$_]))} (0,1);
} until ($m[0] != 1 && $m[1] != 1 && abs(atan2($m[0],1) - atan2($m[1],1)) > 0.2);
@n = map{($_->value)[0]} (@m);
@d = map{($_->value)[1]} (@m);
@f = map{Formula("$m[$_] (x - $h[$_]) + $k[$_]")->reduce} (0,1);
Context("Point");
$solution = Point($x,$y);
$proposed_solution = $solution;
$dropdown = DropDown(["Yes, it is a solution.", "No, it is not a solution."], 0, showInStatic => 0);

############################################################
# Body
############################################################

BEGIN_PGML
Check if the given point is a solution to the given system of two linear equations.

Is [`[$proposed_solution]`] a solution?

[`\newcommand{\amp}{&}
                  \left\{
                    \begin{alignedat}{3}
                      y \amp= [$f[0]]\\
                      y \amp= [$f[1]]
                    \end{alignedat}
                  \right.
                `]

[_]{$dropdown}{5}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
